def main():
    import sys
    input = sys.stdin.read
    data = input().strip().split()
    
    n = int(data[0])  # Size of the linked list
    elements = list(map(int, data[1:n+1]))  # Elements of the linked list
    window_size = int(data[n+1])  # Size of the moving average window
    
    linked_list = LinkedList()
    for element in elements:
        linked_list.push(element)
    
    # Call user logic function and print the output
    result = user_logic(linked_list, window_size)
    print(*result)

if __name__ == "__main__":
    main()